css:
.print-heading {
  text-align: center;
  margin-bottom: 28px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.print-heading p {
  margin: 6px 0 0;
}

.section-heading {
  margin-top: 22px;
  margin-bottom: 10px;
  padding-bottom: 5px;
  border-bottom: 1px solid #b40000;
  font-size: 12pt;
  font-weight: 600;
  page-break-after: avoid;
}

.employee-summary {
  margin-bottom: 18px;
}

.summary-table,
.suspension-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.summary-table td,
.suspension-table th,
.suspension-table td {
  padding: 8px;
  vertical-align: top;
}

.summary-table td,
.suspension-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.summary-table td:last-child,
.suspension-table td:last-child,
.suspension-table th:last-child {
  border-right: none;
}

.summary-table tr:last-child td,
.suspension-table tbody tr:last-child td {
  border-bottom: none;
}

.summary-table tbody tr:nth-child(odd),
.suspension-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.summary-label {
  width: 18%;
  font-weight: 600;
  background-color: #f5f5f5;
}

.suspension-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
  text-align: left;
  font-weight: 600;
}

.suspension-table tr {
  page-break-inside: avoid;
}

.number-column {
  width: 38px;
  text-align: center;
}

.date-column {
  width: 110px;
  white-space: nowrap;
}

.notice-box {
  margin: 18px 0 22px;
  padding: 14px 16px;
  border: 1px solid #ccc;
  border-left-width: 4px;
  border-radius: 6px;
  page-break-inside: avoid;
}

.notice-box p {
  margin: 0 0 10px;
}

.notice-box p:last-child {
  margin-bottom: 0;
}

.precautionary-notice {
  border-left-color: #d58b00;
  background-color: #fffaf0;
}

.punitive-notice {
  border-left-color: #b40000;
  background-color: #fff7f7;
}

.signature-introduction {
  margin-top: 22px;
}

.signature-introduction p {
  margin: 0 0 10px;
}

.signatures {
  margin-top: 28px;
  page-break-inside: auto;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.signatures tr {
  page-break-inside: avoid;
}

.signatures td {
  border: none;
  vertical-align: bottom;
}

.signatures .signature-cell {
  width: 68%;
  padding: 38px 30px 16px 0;
}

.signatures .date-cell {
  width: 32%;
  padding: 38px 0 16px 20px;
}

.signatures .signature-line {
  min-height: 22px;
  border-bottom: 1px solid #222;
}

.signatures .signature-label {
  margin-top: 5px;
  font-size: 10.5pt;
  line-height: 1.3;
}

.signatures .qualifier {
  font-size: 9pt;
  font-style: italic;
}

@page {
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
